对于 Windows 操作系统，你可以使用 `os` 包中的 `GetVersion` 函数来获取版本号：

```go
package main

import (
	"fmt"
	"os"
	"syscall"
	"unsafe"
)

func main() {
	version, err := getWindowsVersion()
	if err != nil {
		fmt.Println("Error:", err)
		os.Exit(1)
	}

	fmt.Println("OS Version:", version)
}

func getWindowsVersion() (string, error) {
	kernel32, err := syscall.LoadLibrary("kernel32.dll")
	if err != nil {
		return "", err
	}
	defer syscall.FreeLibrary(kernel32)

	getVersion, err := syscall.GetProcAddress(kernel32, "GetVersion")
	if err != nil {
		return "", err
	}

	version, _, _ := syscall.Syscall(uintptr(getVersion), 0, 0, 0, 0)
	major := uint8(version)
	minor := uint8(version >> 8)
	build := uint16(version >> 16)
	return fmt.Sprintf("%d.%d.%d", major, minor, build), nil
}
```

